import time
import requests
from collections import deque

class RateLimiter:
    def __init__(self, max_requests, time_window_seconds):
        self.max_requests = max_requests
        self.time_window_seconds = time_window_seconds
        self.request_timestamps = deque()

    def wait_for_permission(self):
        while True:
            current_time = time.time()

            while self.request_timestamps and \
                  self.request_timestamps[0] <= current_time - self.time_window_seconds:
                self.request_timestamps.popleft()

            if len(self.request_timestamps) < self.max_requests:
                break
            else:
                time_to_wait = (self.request_timestamps[0] + self.time_window_seconds) - current_time
                if time_to_wait > 0:
                    time.sleep(time_to_wait)

        self.request_timestamps.append(time.time())

def rate_limited_api_caller(url, method='GET', headers=None, params=None, json=None, data=None, timeout=10, rate_limiter=None):
    if rate_limiter is None:
        raise ValueError("A RateLimiter instance must be provided.")

    rate_limiter.wait_for_permission()

    try:
        if method.upper() == 'GET':
            response = requests.get(url, headers=headers, params=params, timeout=timeout)
        elif method.upper() == 'POST':
            response = requests.post(url, headers=headers, json=json, data=data, timeout=timeout)
        elif method.upper() == 'PUT':
            response = requests.put(url, headers=headers, json=json, data=data, timeout=timeout)
        elif method.upper() == 'DELETE':
            response = requests.delete(url, headers=headers, timeout=timeout)
        else:
            raise ValueError(f"Unsupported HTTP method: {method}")

        response.raise_for_status()
        return response.json()
    except requests.exceptions.RequestException as e:
        print(f"API request failed: {e}")
        return None
    except ValueError as e:
        print(f"Error: {e}")
        return None
